import { collection, addDoc, getDocs, query, where, doc, getDoc, updateDoc, deleteDoc } from 'firebase/firestore';
import { db } from '../config/firebaseConfig';
import { Group, Trip, Event, Expense, Document, PackingItem } from '../types';

/**
 * Creates a new Group document in Firestore.
 * The document ID is auto-generated by Firestore and returned as part of the Group object.
 */
export const createGroup = async (
  name: string,
  createdBy: string
): Promise<Group> => {
  const groupsCollection = collection(db, 'groups');
  const docRef = await addDoc(groupsCollection, {
    name,
    createdBy,
  });
  
  return {
    id: docRef.id,
    name,
    createdBy,
  };
};

/**
 * Creates a new Trip document in Firestore, linking it to a Group via groupId.
 * The document ID is auto-generated by Firestore and returned as part of the Trip object.
 */
export const createTrip = async (
  groupId: string,
  name: string,
  startDate: string,
  endDate: string,
  status: string,
  baseCurrency?: string,
  exchangeRateToILS?: number
): Promise<Trip> => {
  const tripsCollection = collection(db, 'trips');
  const data: any = {
    groupId,
    name,
    startDate,
    endDate,
    status,
  };
  if (baseCurrency !== undefined) data.baseCurrency = baseCurrency;
  if (exchangeRateToILS !== undefined) data.exchangeRateToILS = exchangeRateToILS;

  const docRef = await addDoc(tripsCollection, data);

  return {
    id: docRef.id,
    groupId,
    name,
    startDate,
    endDate,
    status,
    baseCurrency,
    exchangeRateToILS,
  };
};

/**
 * Saves a new Trip for a user.
 * If the user does not have an existing Group (where createdBy === userId),
 * it automatically creates a default Group for them first, then creates the Trip associated with it.
 */
export const saveTripForUser = async (
  userId: string,
  name: string,
  startDate: string,
  endDate: string
): Promise<Trip> => {
  const groupsCollection = collection(db, 'groups');
  const q = query(groupsCollection, where('createdBy', '==', userId));
  const querySnapshot = await getDocs(q);

  let groupId = '';

  if (!querySnapshot.empty) {
    // User already has a group, use the first one
    const firstGroupDoc = querySnapshot.docs[0];
    groupId = firstGroupDoc.id;
  } else {
    // User does not belong to any group, auto-create a default group
    const defaultGroupName = 'My Travel Group';
    const newGroup = await createGroup(defaultGroupName, userId);
    groupId = newGroup.id;
  }

  // Save the trip under the selected group
  return createTrip(groupId, name, startDate, endDate, 'planned');
};

/**
 * Fetches all trips associated with groups created by the specified user.
 */
export const getTripsForUser = async (userId: string): Promise<Trip[]> => {
  const groupsCollection = collection(db, 'groups');
  const qGroup = query(groupsCollection, where('createdBy', '==', userId));
  const groupSnapshot = await getDocs(qGroup);

  if (groupSnapshot.empty) {
    return [];
  }

  const groupIds = groupSnapshot.docs.map((doc) => doc.id);

  // Retrieve trips whose groupId belongs to the user's groups
  const tripsCollection = collection(db, 'trips');
  const qTrips = query(tripsCollection, where('groupId', 'in', groupIds));
  const tripsSnapshot = await getDocs(qTrips);

  return tripsSnapshot.docs.map((doc) => {
    const data = doc.data();
    return {
      id: doc.id,
      groupId: data.groupId,
      name: data.name,
      startDate: data.startDate,
      endDate: data.endDate,
      status: data.status,
      baseCurrency: data.baseCurrency,
      exchangeRateToILS: data.exchangeRateToILS,
    } as Trip;
  });
};

/**
 * Saves a new Event to the 'events' collection in Firestore.
 */
export const createEvent = async (
  tripId: string,
  title: string,
  type: 'flight' | 'hotel' | 'waypoint',
  startTime: string,
  endTime: string,
  latitude?: number,
  longitude?: number,
  bookingReference?: string,
  description?: string,
  flightNumber?: string,
  airline?: string,
  departureTime?: string,
  arrivalTime?: string,
  originAirport?: string,
  destinationAirport?: string,
  hotelUrl?: string,
  checkInTime?: string,
  checkOutTime?: string,
  roomType?: string,
  breakfastIncluded?: boolean,
  distance?: number,
  estimatedTravelTime?: string,
  qrCodeUrl?: string,
  transportMode?: string,
  cost?: number,
  originLatitude?: number,
  originLongitude?: number,
  address?: string,
  routePolyline?: string
): Promise<Event> => {
  const eventsCollection = collection(db, 'events');
  const data: any = {
    tripId,
    title,
    type,
    startTime,
    endTime,
  };
  if (latitude !== undefined) data.latitude = latitude;
  if (longitude !== undefined) data.longitude = longitude;
  if (bookingReference !== undefined) data.bookingReference = bookingReference;
  if (description !== undefined) data.description = description;
  if (flightNumber !== undefined) data.flightNumber = flightNumber;
  if (airline !== undefined) data.airline = airline;
  if (departureTime !== undefined) data.departureTime = departureTime;
  if (arrivalTime !== undefined) data.arrivalTime = arrivalTime;
  if (originAirport !== undefined) data.originAirport = originAirport;
  if (destinationAirport !== undefined) data.destinationAirport = destinationAirport;
  if (hotelUrl !== undefined) data.hotelUrl = hotelUrl;
  if (checkInTime !== undefined) data.checkInTime = checkInTime;
  if (checkOutTime !== undefined) data.checkOutTime = checkOutTime;
  if (roomType !== undefined) data.roomType = roomType;
  if (breakfastIncluded !== undefined) data.breakfastIncluded = breakfastIncluded;
  if (distance !== undefined) data.distance = distance;
  if (estimatedTravelTime !== undefined) data.estimatedTravelTime = estimatedTravelTime;
  if (qrCodeUrl !== undefined) data.qrCodeUrl = qrCodeUrl;
  if (transportMode !== undefined) data.transportMode = transportMode;
  if (cost !== undefined) data.cost = cost;
  if (originLatitude !== undefined) data.originLatitude = originLatitude;
  if (originLongitude !== undefined) data.originLongitude = originLongitude;
  if (address !== undefined) data.address = address;
  if (routePolyline !== undefined) data.routePolyline = routePolyline;

  const docRef = await addDoc(eventsCollection, data);

  return {
    id: docRef.id,
    tripId,
    title,
    type,
    startTime,
    endTime,
    latitude,
    longitude,
    bookingReference,
    description,
    flightNumber,
    airline,
    departureTime,
    arrivalTime,
    originAirport,
    destinationAirport,
    hotelUrl,
    checkInTime,
    checkOutTime,
    roomType,
    breakfastIncluded,
    distance,
    estimatedTravelTime,
    qrCodeUrl,
    transportMode,
    cost,
    originLatitude,
    originLongitude,
    address,
    routePolyline,
  };
};

