/**
 * Saves a new Expense to the 'expenses' collection in Firestore.
 * Requires querying the associated trip document to find the correct groupId first.
 */
export const createExpense = async (
  tripId: string,
  amount: number,
  currency: string,
  category: string,
  description: string
): Promise<Expense> => {
  const tripDocRef = doc(db, 'trips', tripId);
  const tripSnapshot = await getDoc(tripDocRef);
  if (!tripSnapshot.exists()) {
    throw new Error('Associated trip does not exist.');
  }
  const tripData = tripSnapshot.data();
  const groupId = tripData.groupId;

  const expensesCollection = collection(db, 'expenses');
  const docRef = await addDoc(expensesCollection, {
    tripId,
    groupId,
    amount,
    currency,
    category,
    description,
    date: new Date().toISOString().split('T')[0],
  });

  return {
    id: docRef.id,
    tripId,
    groupId,
    amount,
    currency,
    category,
    date: new Date().toISOString().split('T')[0],
    description,
  };
};

/**
 * Fetches all expenses associated with a specific tripId from Firestore.
 */
export const getExpensesForTrip = async (tripId: string): Promise<Expense[]> => {
  const expensesCollection = collection(db, 'expenses');
  const q = query(expensesCollection, where('tripId', '==', tripId));
  const querySnapshot = await getDocs(q);

  return querySnapshot.docs.map((doc) => {
    const data = doc.data();
    return {
      id: doc.id,
      tripId: data.tripId,
      groupId: data.groupId,
      amount: data.amount,
      currency: data.currency,
      category: data.category,
      date: data.date,
      description: data.description,
    } as Expense;
  });
};

/**
 * Saves document metadata to the 'documents' collection in Firestore.
 */
export const saveDocument = async (
  tripId: string,
  name: string,
  downloadUrl: string,
  eventId?: string
): Promise<Document> => {
  const documentsCollection = collection(db, 'documents');
  const data: any = {
    tripId,
    name,
    downloadUrl,
  };
  if (eventId) {
    data.eventId = eventId;
  }

  const docRef = await addDoc(documentsCollection, data);

  return {
    id: docRef.id,
    tripId,
    name,
    downloadUrl,
    ...(eventId ? { eventId } : {}),
  };
};

/**
 * Fetches all document metadata documents associated with a specific tripId from Firestore.
 */
export const getDocumentsForTrip = async (tripId: string): Promise<Document[]> => {
  const documentsCollection = collection(db, 'documents');
  const q = query(documentsCollection, where('tripId', '==', tripId));
  const querySnapshot = await getDocs(q);

  return querySnapshot.docs.map((doc) => {
    const data = doc.data();
    return {
      id: doc.id,
      tripId: data.tripId,
      eventId: data.eventId,
      name: data.name,
      downloadUrl: data.downloadUrl,
    } as Document;
  });
};

/**
 * Creates a new PackingItem document in Firestore under 'packingItems'.
 */
export const createPackingItem = async (
  tripId: string,
  itemName: string,
  category: string
): Promise<PackingItem> => {
  const packingItemsCollection = collection(db, 'packingItems');
  const data = {
    tripId,
    itemName,
    category,
    isPacked: false,
  };
  const docRef = await addDoc(packingItemsCollection, data);
  return {
    id: docRef.id,
    ...data,
  };
};

/**
 * Fetches all packing items associated with a specific tripId from Firestore.
 */
export const getPackingItemsForTrip = async (tripId: string): Promise<PackingItem[]> => {
  const packingItemsCollection = collection(db, 'packingItems');
  const q = query(packingItemsCollection, where('tripId', '==', tripId));
  const querySnapshot = await getDocs(q);

  return querySnapshot.docs.map((doc) => {
    const data = doc.data();
    return {
      id: doc.id,
      tripId: data.tripId,
      itemName: data.itemName,
      category: data.category,
      isPacked: !!data.isPacked,
    } as PackingItem;
  });
};

/**
 * Updates the packed status flag of a specific packing item in Firestore.
 */
export const updatePackingItemPacked = async (
  itemId: string,
  isPacked: boolean
): Promise<void> => {
  const itemDocRef = doc(db, 'packingItems', itemId);
  await updateDoc(itemDocRef, { isPacked });
};

/**
 * Deletes a specific packing item from Firestore.
 */
export const deletePackingItem = async (itemId: string): Promise<void> => {
  const itemDocRef = doc(db, 'packingItems', itemId);
  await deleteDoc(itemDocRef);
};

/**
 * Fetches a single Trip document by its ID.
 */
export const getTrip = async (tripId: string): Promise<Trip | null> => {
  const tripDocRef = doc(db, 'trips', tripId);
  const tripSnapshot = await getDoc(tripDocRef);
  if (!tripSnapshot.exists()) {
    return null;
  }
  const data = tripSnapshot.data();
  return {
    id: tripSnapshot.id,
    groupId: data.groupId,
    name: data.name,
    startDate: data.startDate,
    endDate: data.endDate,
    status: data.status,
    baseCurrency: data.baseCurrency,
    exchangeRateToILS: data.exchangeRateToILS,
  } as Trip;
};

/**
 * Updates the currency settings for a specific trip in Firestore.
 */
export const updateTripSettings = async (
  tripId: string,
  baseCurrency: string,
  exchangeRateToILS: number
): Promise<void> => {
  const tripDocRef = doc(db, 'trips', tripId);
  await updateDoc(tripDocRef, {
    baseCurrency,
    exchangeRateToILS,
  });
};
